  // --- Bibliothèque étirements (100) ---
  etNeckFlex: { name: "Flexion du cou", cue: "Menton vers la poitrine, descends doucement, épaules basses.", detail: { "pos": "Assis ou debout, épaules basses et détendues.", "move": "Amène doucement le menton vers la poitrine, jusqu\u2019à sentir l\u2019étirement à l\u2019arrière du cou.", "avoid": "Ne pas hausser les épaules pendant la flexion \u2014 garde-les basses et relâchées tout le mouvement." }, side: false, type: "hold", secs: 30, muscles: "Trapeze, nuque", articulation: "Cervicales", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Débutant", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etNeckExt: { name: "Extension du cou", cue: "Regarde lentement le plafond, bouche fermée, sans forcer.", detail: { "pos": "Assis ou debout, dos droit.", "move": "Regarde lentement vers le plafond en gardant la bouche fermée, jusqu\u2019à sentir l\u2019étirement à l\u2019avant du cou.", "avoid": "Ne pas forcer l\u2019extension \u2014 arrête-toi dès que tu sens une tension confortable, sans aller plus loin." }, side: false, type: "hold", secs: 15, muscles: "Fléchisseurs du cou", articulation: "Cervicales", materiel: "Aucun", stretchType: "Statique", temps: "15s", niveau: "Débutant", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etNeckRot: { name: "Rotation du cou", cue: "Tourne lentement la tête côté puis l'autre, épaules immobiles.", detail: { "pos": "Assis ou debout, épaules immobiles, dos droit.", "move": "Tourne lentement la tête vers un côté jusqu\u2019à sentir l\u2019étirement, maintiens, puis tourne vers l\u2019autre côté.", "avoid": "Ne pas bouger les épaules pendant la rotation \u2014 seule la tête doit tourner, le reste du corps reste stable." }, side: true, type: "hold", secs: 30, muscles: "Trapeze, nuque", articulation: "Cervicales", materiel: "Aucun", stretchType: "Dynamique", temps: "30s", niveau: "Débutant", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etLevScap: { name: "Étirement élévateur de la scapula", cue: "Menton vers l'aisselle, main tire doucement la tête en diagonale.", detail: { "pos": "Assis ou debout, tête légèrement inclinée, menton orienté vers une aisselle.", "move": "Utilise une main pour tirer très doucement la tête en diagonale vers l\u2019aisselle, jusqu\u2019à sentir l\u2019étirement sur le côté du cou.", "avoid": "Ne jamais tirer fort sur la tête \u2014 ce muscle est sensible, une traction légère et progressive est essentielle." }, side: true, type: "hold", secs: 30, muscles: "Trapeze, epaules", articulation: "Cervicales", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Intermédiaire", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etArmsCross: { name: "Bras en croix", cue: "Bras tendus en croix, ouvre la poitrine vers l'arrière, omoplates serrées.", detail: { "pos": "Debout ou assis, bras tendus \u00e9cart\u00e9s en croix.", "move": "Ouvre la poitrine vers l\u2019arri\u00e8re en serrant les omoplates l\u2019une vers l\u2019autre, tiens la position.", "avoid": "Ne pas hausser les \u00e9paules vers les oreilles \u2014 garde-les basses pendant tout l\u2019\u00e9tirement." }, side: false, type: "hold", secs: 30, muscles: "Pectoraux, épaules", articulation: "Épaule", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Débutant", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etPecDoor: { name: "Pectoral encadrement de porte", cue: "Avant-bras contre le montant, avance le buste pour ouvrir la poitrine.", detail: { "pos": "Debout, avant-bras vertical contre un montant de porte ou un mur, coude à hauteur d\u2019épaule.", "move": "Avance doucement le buste et tourne-le à l\u2019opposé du bras pour ouvrir la poitrine, jusqu\u2019à sentir l\u2019étirement.", "avoid": "Ne pas lever l\u2019épaule vers l\u2019oreille \u2014 garde-la basse et relâchée." }, side: true, type: "hold", secs: 30, muscles: "Pectoraux", articulation: "Épaule", materiel: "Encadrement de porte", stretchType: "Statique", temps: "30s", niveau: "Débutant", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etTricepsOH: { name: "Triceps au-dessus de la tête", cue: "Coude plié derrière la tête, l'autre main pousse le coude vers le bas.", detail: { "pos": "Debout ou assis, un coude pli\u00e9 derri\u00e8re la t\u00eate, main pendant entre les omoplates.", "move": "Utilise l\u2019autre main pour pousser doucement le coude vers le bas et l\u2019int\u00e9rieur, jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement du triceps.", "avoid": "Ne pas tirer le coude trop loin vers l\u2019int\u00e9rieur \u2014 une pression douce et progressive suffit." }, side: true, type: "hold", secs: 30, muscles: "Triceps", articulation: "Épaule", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Débutant", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etLatWall: { name: "Grand dorsal au mur", cue: "Mains au mur en hauteur, recule le bassin, dos long, flancs étirés.", detail: { "pos": "Debout face à un mur, mains posées en hauteur contre le mur.", "move": "Recule le bassin vers l\u2019arrière en gardant les bras tendus et le dos long, pour étirer les flancs et le grand dorsal.", "avoid": "Ne pas plier les bras \u2014 garde-les tendus pour transmettre tout l\u2019étirement au dos et aux flancs." }, side: false, type: "hold", secs: 30, muscles: "Grand dorsal", articulation: "Épaule, colonne", materiel: "Mur", stretchType: "Statique", temps: "30s", niveau: "Débutant", sub: "Cou & épaules", etir: true, cat: "mobilite" },
  etShoulderBack: { name: "Épaules bras derrière", cue: "Mains jointes derrière le dos, monte les bras tendus, poitrine ouverte.", detail: { "pos": "Debout ou assis, mains jointes derri\u00e8re le dos, bras tendus.", "move": "Monte les bras tendus derri\u00e8re toi en ouvrant la poitrine, jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement \u00e0 l\u2019avant des \u00e9paules.", "avoid": "Ne pas cambrer le bas du dos pour monter plus haut \u2014 limite l\u2019amplitude \u00e0 ce que permettent tes \u00e9paules." }, side: false, type: "hold", secs: 30, muscles: "Épaules, pectoraux", articulation: "Épaule", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Intermédiaire", sub: "Cou & épaules", etir: true, cat: "mobilite" },
