  etHipOpenWall: { name: "Ouverture hanche mur", cue: "Sur le dos jambes au mur, écarte les jambes en V, gravité ouvre les hanches.", detail: { "pos": "Allongé sur le dos, fesses proches d\u2019un mur, jambes levées appuyées contre le mur.", "move": "Laisse les jambes s\u2019écarter doucement en V sous l\u2019effet de la gravité, sans forcer.", "avoid": "Ne pas forcer l\u2019écartement avec les mains \u2014 laisse le poids des jambes et la relaxation faire le travail progressivement." }, side: false, type: "hold", secs: 60, muscles: "Adducteurs", articulation: "Hanche", materiel: "Mur", stretchType: "Statique", temps: "60s", niveau: "Débutant", sub: "Hanches & bassin", etir: true, cat: "mobilite" },
  etCrossPelvis: { name: "Étirement croisé bassin", cue: "Sur le dos, croise une cheville sur le genou opposé, rapproche les cuisses.", detail: { "pos": "Allong\u00e9 sur le dos, une cheville croisée sur le genou opposé.", "move": "Rapproche les deux cuisses vers la poitrine en tenant l\u2019arrière de la cuisse au sol, jusqu\u2019à sentir l\u2019étirement de la fesse.", "avoid": "Ne pas forcer si une douleur vive apparaît au genou \u2014 réduis l\u2019amplitude du rapprochement." }, side: true, type: "hold", secs: 40, muscles: "Fessiers, piriforme", articulation: "Hanche", materiel: "Aucun", stretchType: "Statique", temps: "40s", niveau: "Débutant", sub: "Hanches & bassin", etir: true, cat: "mobilite" },
  etHamSit: { name: "Ischios assis", cue: "Assis jambe tendue, penche le buste vers le pied, dos long.", detail: { "pos": "Assis, une jambe tendue devant toi, l\u2019autre pli\u00e9e sur le c\u00f4t\u00e9.", "move": "Penche le buste vers le pied de la jambe tendue en gardant le dos long, jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement de l\u2019ischio.", "avoid": "Ne pas arrondir le dos pour descendre plus bas \u2014 mieux vaut moins d\u2019amplitude avec un dos droit." }, side: true, type: "hold", secs: 30, muscles: "Ischio-jambiers", articulation: "Hanche, genou", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Débutant", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
  etCalfWallStraight: { name: "Mollet mur jambe tendue", cue: "Mains au mur, jambe arrière tendue talon au sol, avance le bassin.", detail: { "pos": "Face \u00e0 un mur, mains en appui, jambe arri\u00e8re tendue, talon plaqu\u00e9 au sol.", "move": "Avance le bassin vers le mur en gardant la jambe arri\u00e8re bien tendue, jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement du mollet.", "avoid": "Ne pas laisser le talon arri\u00e8re se soulever \u2014 c\u2019est le contact talon-sol qui cr\u00e9e l\u2019\u00e9tirement." }, side: true, type: "hold", secs: 30, muscles: "Gastrocnémien", articulation: "Cheville", materiel: "Mur", stretchType: "Statique", temps: "30s", niveau: "Débutant", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
