  etTibAnt: { name: "Tibial antérieur mur", cue: "Pointe de pied au sol derrière, pousse le dessus du pied vers le sol.", detail: { "pos": "Debout, une jambe en arri\u00e8re, pointe du pied pos\u00e9e au sol derri\u00e8re toi.", "move": "Pousse le dessus du pied vers le sol pour \u00e9tirer l\u2019avant du tibia, jusqu\u2019\u00e0 sentir la tension.", "avoid": "Ne pas forcer si une crampe appara\u00eet \u2014 r\u00e9duis la pression et reprends progressivement." }, side: true, type: "hold", secs: 30, muscles: "Mollets, cheville", articulation: "Cheville", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Intermédiaire", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
