  etDorsiflex: { name: "Dorsiflexion", cue: "Assis jambe tendue, ramène la pointe vers toi, mollet étiré.", detail: { "pos": "Assis, jambe tendue devant toi.", "move": "Ram\u00e8ne la pointe du pied vers toi en gardant le genou tendu, jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement du mollet.", "avoid": "Ne pas plier le genou \u2014 la jambe tendue est essentielle pour cibler le mollet." }, side: true, type: "hold", secs: 15, muscles: "Mollet", articulation: "Cheville", materiel: "Aucun", stretchType: "Statique", temps: "15s", niveau: "Débutant", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
  etCalfStep: { name: "Mollet sur marche", cue: "Avant-pied sur une marche, laisse le talon descendre sous le niveau.", detail: { "pos": "Avant du pied pos\u00e9 sur le bord d\u2019une marche, talon dans le vide.", "move": "Laisse le talon descendre sous le niveau de la marche jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement du mollet, maintiens la position.", "avoid": "Ne pas descendre brusquement \u2014 laisse le poids du corps \u00e9tirer progressivement, sans \u00e0-coup." }, side: true, type: "hold", secs: 30, muscles: "Mollets", articulation: "Cheville", materiel: "Marche", stretchType: "Statique", temps: "30s", niveau: "Intermédiaire", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
  etTowelFoot: { name: "Pied avec serviette", cue: "Assis jambe tendue, serviette autour du pied, tire la pointe vers toi.", detail: { "pos": "Assis, jambe tendue devant toi, serviette enroul\u00e9e autour de l\u2019avant du pied.", "move": "Tire doucement la pointe du pied vers toi avec la serviette, jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement du mollet.", "avoid": "Ne pas plier le genou \u2014 garde la jambe tendue pour cibler efficacement le mollet." }, side: true, type: "hold", secs: 30, muscles: "Mollets, plante", articulation: "Cheville", materiel: "Serviette", stretchType: "PNF", temps: "30s", niveau: "Débutant", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
  etToes: { name: "Étirement orteils", cue: "À genoux orteils repliés sous le pied, assieds-toi doucement en arrière.", detail: { "pos": "\u00c0 genoux, orteils repli\u00e9s sous les pieds.", "move": "Assieds-toi doucement vers l\u2019arri\u00e8re sur les talons, en laissant le poids du corps \u00e9tirer progressivement les orteils.", "avoid": "Ne pas t\u2019asseoir trop vite \u2014 cette zone est sensible, descends lentement et arr\u00eate-toi si \u00e7a devient inconfortable." }, side: false, type: "hold", secs: 30, muscles: "Orteils, plante du pied", articulation: "Pied", materiel: "Aucun", stretchType: "Statique", temps: "30s", niveau: "Intermédiaire", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
  etHamFloss: { name: "Hamstring Flossing", cue: "Sur le dos jambe levée, alterne flexion/extension du genou et de la cheville.", detail: { "pos": "Allong\u00e9 sur le dos, une jambe lev\u00e9e tenue \u00e0 deux mains ou avec une sangle.", "move": "Alterne flexion et extension du genou et de la cheville en gardant la jambe globalement tendue, pour mobiliser le nerf et le muscle ensemble.", "avoid": "Ne pas forcer l\u2019extension compl\u00e8te si \u00e7a tire trop \u2014 le mouvement doit rester fluide et sans douleur vive." }, side: true, type: "hold", secs: 30, muscles: "Ischio-jambiers, nerf sciatique", articulation: "Hanche, genou", materiel: "Aucun", stretchType: "Dynamique", temps: "30s", niveau: "Intermédiaire", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
  etRunnerLunge: { name: "Fente du coureur", cue: "Grande fente, mains au sol de part et d'autre du pied avant, bassin bas.", detail: { "pos": "Grande fente, mains pos\u00e9es au sol de part et d\u2019autre du pied avant.", "move": "Abaisse le bassin pr\u00e8s du sol en gardant les mains stables, jusqu\u2019\u00e0 sentir l\u2019\u00e9tirement profond de la hanche arri\u00e8re.", "avoid": "Ne pas laisser le genou avant d\u00e9passer largement les orteils \u2014 ajuste la distance entre les pieds si besoin." }, side: true, type: "hold", secs: 40, muscles: "Fléchisseurs, adducteurs", articulation: "Hanche", materiel: "Aucun", stretchType: "Statique", temps: "40s", niveau: "Intermédiaire", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
