  etSquatAssist: { name: "Squat profond assisté", cue: "En squat profond, tiens un appui devant pour t'aider à rester bas et détendu.", detail: { "pos": "En squat profond, talons au sol, un appui stable devant toi (poteau, cadre de porte).", "move": "Tiens l\u2019appui pour t\u2019aider \u00e0 rester bas et d\u00e9tendu dans la position, en laissant le poids du corps relâcher progressivement.", "avoid": "Ne pas te reposer enti\u00e8rement sur l\u2019appui \u2014 il doit juste t\u2019aider \u00e0 garder l\u2019\u00e9quilibre, pas porter ton poids." }, side: false, type: "hold", secs: 45, muscles: "Hanches, chevilles, adducteurs", articulation: "Hanche, cheville", materiel: "Appui/poteau", stretchType: "Statique", temps: "45s", niveau: "Débutant", sub: "Jambes, genoux & chevilles", etir: true, cat: "mobilite" },
